import numpy as npimport cv2from matplotlib import pyplot as pltfrom scipy import ndimagefrom skimage import io, color, measurefrom skimage.segmentation import clear_border""""""img = cv2.imread("../data/grains2.jpg")img1 = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)pixels_to_um = 0.5 #1 pixel = 0.5 micrometersplt.hist(img1.flat, bins=100, range=(0, 255))ret, thresh = cv2.threshold(    img1,    0,    255,    cv2.THRESH_BINARY + cv2.THRESH_OTSU)kernel = np.ones((3,3), np.uint8)opening = cv2.morphologyEx(thresh, cv2.MORPH_OPEN, kernel, iterations = 1)opening = clear_border(opening)distance = cv2.distanceTransform(opening, cv2.DIST_L2, 3)ret2, thresh2 = cv2.threshold(distance, 0.2*distance.max(),255,0)sure_fg = np.uint8(thresh2)sure_bg = cv2.dilate(opening, kernel, iterations =1)unknown = cv2.subtract(sure_bg,sure_fg)ret3, markers = cv2.connectedComponents(sure_fg)markers +=10markers[unknown==255] = 0plt.figure(figsize = (16,8))plt.subplot(1,2,1)plt.imshow(opening, cmap = 'gray')plt.title("Opening")plt.subplot(1,2,2)plt.imshow(sure_bg, cmap = 'gray')plt.title("Opening")plt.figure(figsize = (16,8))plt.subplot(1,2,1)plt.imshow(sure_bg, cmap = 'gray')plt.title("Sure_BG")plt.subplot(1,2,2)plt.imshow(sure_fg, cmap = 'gray')plt.title("Sure_FG")plt.figure()plt.imshow(unknown, cmap='gray')plt.title("Unknown")markers = markers.astype(np.int32)markers = cv2.watershed(img, markers)print(np.unique(markers))#-1, 10, 11, 12, ..plt.figure()plt.imshow(markers, cmap='jet')plt.title("Watershed")img[markers == -1] = [0, 255, 255]img2 = color.label2rgb(markers, bg_label=0)img2 = color.label2rgb(markers, bg_label=0)plt.figure()plt.imshow(img2)plt.title("Colored Labels")